PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE articles (     id INTEGER PRIMARY KEY AUTOINCREMENT,     slug TEXT UNIQUE NOT NULL,     title TEXT NOT NULL,     subtitle TEXT,     author TEXT,     published_at DATETIME DEFAULT CURRENT_TIMESTAMP,     read_time_minutes INTEGER,     image_url TEXT,     seo_description TEXT,     tags TEXT,     content_html TEXT NOT NULL , image_copyright TEXT, lexical_matrix TEXT, total_views INTEGER DEFAULT 0, total_reads INTEGER DEFAULT 0, total_shares INTEGER DEFAULT 0, avg_time_spent REAL DEFAULT 0, engagement_score REAL DEFAULT 0, trending_velocity REAL DEFAULT 0);
CREATE TABLE authors (     id INTEGER PRIMARY KEY AUTOINCREMENT,     name TEXT UNIQUE NOT NULL,     role TEXT,     bio TEXT,     avatar_url TEXT,     social_link TEXT , "in-app_link" TEXT);
CREATE TABLE subscribers ( id INTEGER PRIMARY KEY AUTOINCREMENT, email TEXT UNIQUE NOT NULL, subscribed_at DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE IF NOT EXISTS "subscribers_contribute"(
  "id" INTEGER,
  "email" TEXT,
  "subscribed_at" TEXT,
  PRIMARY KEY ("id")
);
CREATE TABLE algo_user_sessions (     session_id TEXT PRIMARY KEY,     first_seen_at DATETIME,     last_seen_at DATETIME,     total_interactions INTEGER DEFAULT 0,     total_time_spent INTEGER DEFAULT 0,     user_agent TEXT,     platform TEXT,     language TEXT,     referrer TEXT,     screen_width INTEGER,     screen_height INTEGER,     window_width INTEGER,     window_height INTEGER,     timezone TEXT,     connection_type TEXT,     device_memory REAL,     hardware_concurrency INTEGER,     lexical_history TEXT , interaction_history TEXT, is_aggregated INTEGER DEFAULT 0);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX idx_articles_slug ON articles (slug);
CREATE INDEX idx_articles_date ON articles (published_at DESC);
CREATE INDEX idx_algo_user_sessions_last_seen ON algo_user_sessions(last_seen_at);
